/**
 * B1–B2 level words for "word of the day". Deterministic per date; zero API calls.
 * One entry per day for many years.
 */
export interface DailyWordEntry {
    word: string;
    type: string;
    meaning: string;
    example: string;
}

// Hash string to a non-negative integer (deterministic).
function hashDate(s: string): number {
    let h = 0;
    for (let i = 0; i < s.length; i++) {
        h = ((h << 5) - h) + s.charCodeAt(i);
        h |= 0;
    }
    return Math.abs(h);
}

