/** Deterministic word of the day for a given date (YYYY-MM-DD). No API calls. */
export function getDailyWordForDate(date: string): DailyWordEntry {
    const index = hashDate(date) % DAILY_WORDS.length;
    return DAILY_WORDS[index];
}
